sql.where:
deleted = '0'



    AND transaction_type = #{dto.transactionType}




    AND category_id = #{dto.categoryId}


    AND category = #{dto.category}




    AND sub_category_id = #{dto.subCategoryId}


    AND sub_category = #{dto.subCategory}




    AND payment_channel = #{dto.paymentChannel}




    AND manual_entry = #{dto.manualEntry}




    AND include_in_statistics = #{dto.includeInStatistics}




    AND amount_type = #{dto.amountType}




    AND (
        transaction_desc LIKE CONCAT('%', #{dto.keywords}, '%')
            OR manual_remark LIKE CONCAT('%', #{dto.keywords}, '%')
        )




    AND id IN (
    SELECT bill_id
    FROM bill_tag_relation
    WHERE tag_id IN

        #{tagId}

    AND deleted = '0'
    )




    AND (income_amount >= #{dto.minAmount} OR expense_amount >= #{dto.minAmount})




    AND (income_amount <= #{dto.maxAmount} OR expense_amount <= #{dto.maxAmount})




    AND transaction_date >= #{dto.startDate}




    AND transaction_date <= #{dto.endDate}

mapper.select:
SELECT category, SUM(amount) AS amount, COUNT(*) AS count FROM ( SELECT COALESCE(category, '未分类') AS category, CASE WHEN amount_type = 'INCOME' THEN income_amount WHEN amount_type = 'EXPENSE' THEN expense_amount ELSE 0 END AS amount FROM bill WHERE deleted = '0' AND include_in_statistics = '1' AND amount_type = #{amountType} AND YEAR(transaction_date) = #{year}
AND MONTH(transaction_date) = #{month}
) AS data GROUP BY category ORDER BY amount DESC
